const input = $input.first().json || {};
const normalizeString = (value) => (typeof value === 'string' ? value.trim() : '');
const normalizeEmail = (value) => normalizeString(value).toLowerCase();

let fromName = '';
let fromEmail = '';

if (Array.isArray(input.from) && input.from[0] && typeof input.from[0] === 'object') {
  fromName = normalizeString(input.from[0].name || '');
  fromEmail = normalizeEmail(input.from[0].address || '');
} else if (input.from && typeof input.from === 'object') {
  fromName = normalizeString(input.from.name || '');
  fromEmail = normalizeEmail(input.from.address || input.from.email || '');
} else if (typeof input.from === 'string') {
  const rawFrom = input.from;
  const match = rawFrom.match(/^(.*)<([^>]+)>$/);
  if (match) {
    fromName = normalizeString(match[1].replace(/\"/g, ''));
    fromEmail = normalizeEmail(match[2]);
  } else {
    fromEmail = normalizeEmail(rawFrom);
  }
}

const subject = normalizeString(input.subject || input?.headers?.subject || '');
const plainTextBody = normalizeString(
  input.text ||
  input.textPlain ||
  input.plainTextBody ||
  input.body ||
  input.html ||
  ''
);
const messageId = normalizeString(
  input.messageId || input?.headers?.['message-id'] || ''
);

return [{
  json: {
    ...input,
    messageId,
    subject,
    plainTextBody,
    fromName,
    fromEmail
  }
}];

const input = $input.first().json || {};
const timeZone = $env.N8N_TZ || 'Europe/Berlin';
const berlinDate = new Date().toLocaleDateString('sv-SE', { timeZone });
const dailyKey = `email-ai:${berlinDate}`;
const dailyLimit = 10;

const staticData = getWorkflowStaticData('global');
if (!staticData.emailAiCounters || typeof staticData.emailAiCounters !== 'object') {
  staticData.emailAiCounters = {};
}

const rawCount = Number(staticData.emailAiCounters[dailyKey] || 0);
const dailyCount = Number.isFinite(rawCount) ? rawCount : 0;

return [{
  json: {
    ...input,
    dailyKey,
    dailyLimit,
    dailyCount,
    limitReached: dailyCount >= dailyLimit
  }
}];

const input = $input.first().json || {};
const staticData = getWorkflowStaticData('global');
if (!staticData.emailAiCounters || typeof staticData.emailAiCounters !== 'object') {
  staticData.emailAiCounters = {};
}

const dailyKey = String(input.dailyKey || '');
if (dailyKey === '') {
  throw new Error('Missing dailyKey for persistent counter increment.');
}

const nextCount = Number(staticData.emailAiCounters[dailyKey] || 0) + 1;
staticData.emailAiCounters[dailyKey] = nextCount;

return [{
  json: {
    ...input,
    dailyCountAfterIncrement: nextCount
  }
}];

