const response = $input.first().json;
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || response?.text || '';
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  return [{
    json: {
      parseError: true,
      failureClass: 'validation',
      failureReason: `Gemini response is not valid JSON: ${error.message}`,
      rawGeminiText: rawText
    }
  }];
}
return [{ json: { parseError: false, geminiPayload: parsed, rawGeminiText: rawText } }];

const item = $input.first().json;
if (item.parseError === true) {
  return [{ json: { ...item, schemaValid: false } }];
}

const payload = item.geminiPayload && typeof item.geminiPayload === 'object' ? item.geminiPayload : {};
const normalized = {
  title: typeof payload.title === 'string' ? payload.title.trim() : '',
  label: typeof payload.label === 'string' ? payload.label.trim() : '',
  creatorName: typeof payload.creatorName === 'string' ? payload.creatorName.trim() : '',
  creatorEmail: typeof payload.creatorEmail === 'string' ? payload.creatorEmail.trim().toLowerCase() : '',
  priority: typeof payload.priority === 'string' ? payload.priority.trim().toLowerCase() : '',
  description: typeof payload.description === 'string' ? payload.description.trim() : ''
};

const errors = [];
const allowedLabels = ['User Story', 'Technical Task'];
const allowedPriorities = ['low', 'medium', 'urgent'];

if (normalized.title.length < 3 || normalized.title.length > 120) errors.push('title must be 3..120 chars');
if (!allowedLabels.includes(normalized.label)) errors.push('label invalid');
if (normalized.creatorName.length < 2 || normalized.creatorName.length > 120) errors.push('creatorName must be 2..120 chars');
if (!/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(normalized.creatorEmail)) errors.push('creatorEmail invalid');
if (!allowedPriorities.includes(normalized.priority)) errors.push('priority invalid');
if (normalized.description.length < 3 || normalized.description.length > 2000) errors.push('description must be 3..2000 chars');

return [{
  json: {
    ...item,
    geminiPayload: normalized,
    schemaValid: errors.length === 0,
    schemaErrors: errors,
    failureClass: errors.length === 0 ? '' : 'validation',
    failureReason: errors.length === 0 ? '' : errors.join(' | ')
  }
}];

const item = $input.first().json;
const payload = item.geminiPayload;
const category = $env.JOIN_EMAIL_TASK_CATEGORY || 'category-4';
const taskId = Date.now();
const task = {
  id: taskId,
  type: payload.label,
  title: payload.title,
  description: payload.description,
  subtasks: [],
  assignedTo: [],
  category,
  priority: payload.priority,
  dueDate: '',
  images: [],
  source: 'email-ai',
  aiGenerated: true,
  externalCreatorName: payload.creatorName,
  externalCreatorEmail: payload.creatorEmail,
  createdAt: new Date().toISOString()
};
return [{ json: { ...item, task } }];
